const PHPDUP_PHAR_COMMIT   = 'b4386bb6';
const PHPDUP_PHAR_BRANCH   = 'master';

\Phar::interceptFileFuncs();

set_error_handler(static function (int $code, string $msg) use (&$error): void {
    $error = $msg;
});

$error = null;
$pharPath = \Phar::running(true);
restore_error_handler();

if ($error !== null) {
    fwrite(STDERR, "phpdup: phar environment error: {$error}
");
