}

if ($pharPath === '') {
    fwrite(STDERR, "phpdup: must be run from inside the phar
");
    exit(1);
}

$autoload = 'phar://' . $pharPath . '/vendor/autoload.php';
if (!is_file($autoload)) {
    // Fallback: scan for autoload in phar root
    $dir = new \RecursiveDirectoryIterator('phar://' . $pharPath);
    foreach (new \RecursiveIteratorIterator($dir) as $file) {
        if ($file->getBasename() === 'autoload.php') {
            $autoload = $file->getPathname();
            break 2;
        }
    }
    fwrite(STDERR, "phpdup: autoload not found inside phar
");
    exit(1);
}

require $autoload;

use Symfony\Component\Console\Application;
use Phpdup\Cli\Command;
use Phpdup\Cli\UpdateCommand;
use Phpdup\Cli\CompletionCommand;

$app = new Application('phpdup', PHPDUP_PHAR_VERSION);
$app->add(new Command());
$app->add(new UpdateCommand());
$app->add(new CompletionCommand());
$app->setDefaultCommand((new Command())->getName(), false);
exit($app->run());